class Solution(object):
    def minimumBeautifulSubstrings(self, s):
        # Precompute all binary representations of powers of 5 up to length 15
        powers = set()
        x = 1
        while x < (1 << 15):
            powers.add(bin(x)[2:])
            x *= 5

        n = len(s)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0

        for i in range(1, n + 1):
            for j in range(i):
                sub = s[j:i]
                if sub[0] == '1' and sub in powers:
                    if dp[j] != INF:
                        dp[i] = min(dp[i], dp[j] + 1)

        return dp[n] if dp[n] != INF else -1
